Host: yourserver.com
→ 200 OK: [{"id":1,"name":"Alice","email":"alice@example.com"}, ...]
```

**Fix:** Protect the route with an authentication middleware. Example using JWT:

```js
const jwt = require('jsonwebtoken');

function authenticate(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(403).json({ error: 'Forbidden' });
  }
}

// Apply to sensitive routes
app.get('/users', authenticate, (req, res) => { ... });
```

---

#### 2. Missing Security Headers (OWASP A05: Security Misconfiguration)

Express does not set secure HTTP headers by default. Without them, the app is vulnerable to:
- **Clickjacking** (missing `X-Frame-Options`)
- **MIME-type sniffing attacks** (missing `X-Content-Type-Options`)
- **XSS via browser** (missing `Content-Security-Policy`)
- **Leaking server info** (`X-Powered-By: Express` is exposed by default)

**Fix:** Add `helmet`:

```js
const helmet = require('helmet');
app.use(helmet()); // Sets ~15 security headers automatically
```

This adds `Strict-Transport-Security`, `X-Frame-Options: DENY`, `X-Content-Type-Options: nosniff`, `Content-Security-Policy`, and removes `X-Powered-By`, among others.

---

