const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // max 100 requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

app.use(limiter); // Apply globally, or per-route as needed
```

---

#### 4. No CORS Policy (OWASP A05)

No CORS configuration means Express's default behavior applies — in practice, browsers will block cross-origin reads, but there is no explicit policy. When credentials or sensitive operations are added, a misconfigured CORS policy becomes a serious vulnerability.

