**Recommendation:** Add an authentication middleware (e.g., JWT or session-based) and verify it before serving sensitive data.

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer <token>
  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(403).json({ error: 'Forbidden' });
  }
}

// Apply to protected routes
app.get('/users', requireAuth, (req, res) => {
  res.json([...]);
});
```

---

### 🔴 2. Missing Security Headers (OWASP A05 — Security Misconfiguration)

**Issue:** No HTTP security headers are set. This exposes the app to clickjacking, MIME-sniffing, XSS via reflected content, and information leakage (Express advertises itself via `X-Powered-By`).

**Recommendation:** Use `helmet` to set safe defaults in one line:

```js
const helmet = require('helmet');
app.use(helmet());
// This sets: X-Content-Type-Options, X-Frame-Options, Strict-Transport-Security,
// Content-Security-Policy, X-DNS-Prefetch-Control, and removes X-Powered-By, etc.
```

At minimum, manually remove the fingerprinting header:

```js
app.disable('x-powered-by'); // Hides "Express" from attackers
```

---

### 🔴 3. No Rate Limiting (OWASP A04 — Insecure Design)

**Issue:** All endpoints accept unlimited requests. This enables brute-force attacks, credential stuffing, and denial-of-service.

**Recommendation:** Apply `express-rate-limit` globally and with stricter limits on sensitive routes:

```js
const rateLimit = require('express-rate-limit');

// Global limiter
app.use(rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
}));

// Stricter limiter for auth routes (when added)
const authLimiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 10 });
app.use('/login', authLimiter);
```

---

### 🟠 4. No Input Validation or Body Parsing (OWASP A03 — Injection)

**Issue:** There is no `express.json()` or `express.urlencoded()` middleware, and no input validation library. When POST/PUT routes are added (as they inevitably will be), this creates an immediate injection surface — query injection, prototype pollution, and type confusion bugs.

**Recommendation:** Add body parsing with size limits and a validation layer from day one:

```js
// Limit body size to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Use express-validator for any route that accepts input
const { body, validationResult } = require('express-validator');

app.post('/users',
  requireAuth,
  body('email').isEmail().normalizeEmail(),
  body('name').trim().isLength({ min: 1, max: 100 }).escape(),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    // ... safe to use req.body here
  }
);
```

---

### 🟠 5. CORS Not Configured (OWASP A05 — Security Misconfiguration)

**Issue:** Express's default CORS behavior is permissive. Without an explicit CORS policy, cross-origin requests from any domain may succeed depending on the client context, and there is no protection against CSRF via cross-origin forms.

**Recommendation:** Explicitly configure CORS with an allowlist:

```js
const cors = require('cors');

const corsOptions = {
  origin: ['https://app.yourdomain.com'],  // Explicit allowlist — not '*'
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  credentials: true,
  maxAge: 86400, // Cache preflight for 24h
};

app.use(cors(corsOptions));
```

---

### 🟠 6. No Error Handling Middleware (OWASP A05 — Security Misconfiguration)

**Issue:** Unhandled errors in Express will either crash the process or cause Express to send a default error response that may **leak a stack trace** in development (and sometimes production). There is no global error handler.

**Recommendation:** Add a centralised error handler as the **last** middleware:

```js
// Catch-all 404
app.use((req, res, next) => {
  res.status(404).json({ error: 'Not found' });
});

// Global error handler — must have 4 parameters
app.use((err, req, res, next) => {
  // Log internally, never expose internals to clients
  console.error({ message: err.message, stack: err.stack, path: req.path });

  const statusCode = err.status || err.statusCode || 500;
  res.status(statusCode).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'  // Safe
      : err.message,             // Verbose only in dev
  });
});
```

---

### 🟠 7. Sensitive Data Exposure — PII in Response (OWASP A02)

**Issue:** The `/users` route returns email addresses. Even if authentication were added, responses returning bulk PII with no pagination or field filtering violate data minimisation principles (GDPR Article 5, CCPA).

**Recommendation:**
- Return only the fields the caller needs (use a DTO/projection)
- Add pagination to prevent bulk data extraction
- Redact or hash sensitive fields in list views

```js
app.get('/users', requireAuth, async (req, res) => {
  const { page = 1, limit = 20 } = req.query;
  const users = await UserService.list({ page: +page, limit: Math.min(+limit, 100) });

  // Return only non-sensitive fields in list view
  const safeUsers = users.map(({ id, name }) => ({ id, name })); // no email in list
  res.json(safeUsers);
});
```

---

### 🟡 8. No HTTPS / TLS Enforcement (OWASP A02 / A05)

**Issue:** The app listens on plain HTTP port 3000 with no TLS and no redirect from HTTP → HTTPS. Credentials and session tokens transmitted over HTTP are vulnerable to interception.

**Recommendation:**
- Terminate TLS at a reverse proxy (Nginx, Caddy, or a load balancer) — preferred for production
- Or configure HTTPS directly in Node:

```js
const https = require('https');
const fs = require('fs');

https.createServer({
  key:  fs.readFileSync(process.env.TLS_KEY_PATH),
  cert: fs.readFileSync(process.env.TLS_CERT_PATH),
}, app).listen(443);

// Redirect HTTP to HTTPS
const http = require('http');
http.createServer((req, res) => {
  res.writeHead(301, { Location: `https://${req.headers.host}${req.url}` });
  res.end();
}).listen(80);
```

- Additionally, once on HTTPS, enforce it via Helmet's HSTS header (already included if you use `helmet()`).

---

### 🟡 9. Listening on All Interfaces (OWASP A05)

**Issue:** `app.listen(3000)` binds to `0.0.0.0` (all network interfaces). In a cloud or container environment, this may inadvertently expose the app on a network interface that should be internal-only.

**Recommendation:** Bind explicitly to `127.0.0.1` if the app sits behind a reverse proxy, or to a specific internal IP:

```js
app.listen(3000, '127.0.0.1', () => {
  console.log('Server running on port 3000 (localhost only)');
});
```

---

### 🟡 10. No Logging or Audit Trail (OWASP A09 — Security Logging Failures)

**Issue:** There is no access logging, error logging, or audit trail. Security events (failed auth, invalid input, server errors) are invisible, making incident response impossible.

**Recommendation:** Use a structured logger like `pino` with `pino-http`:

```js
const pino = require('pino');
const pinoHttp = require('pino-http');

const logger = pino({ level: process.env.LOG_LEVEL || 'info' });
app.use(pinoHttp({ logger }));

// Logs every request: method, url, status, response time, IP
```

**Important:** Never log raw request bodies, passwords, tokens, or full Authorization headers.

---

### 🟢 11. No `package.json` / Dependency Management (OWASP A06 — Vulnerable Components)

**Issue:** There is no `package.json` in the project directory. Without it:
- Dependency versions are untracked and unaudited
- `npm audit` cannot be run to catch known CVEs
- The build is not reproducible

**Recommendation:**

```bash
npm init -y
npm install express helmet cors express-rate-limit express-validator jsonwebtoken pino pino-http
npm audit               # Check for known CVEs immediately
npm audit fix           # Auto-fix where possible
```

Pin exact versions in production by committing `package-lock.json` and running `npm ci` in CI/CD.

---

### 🟢 12. Environment / Secret Hygiene

**Issue:** A `.env.test` file is present in the project directory. Environment files must **never** be committed to source control, as they can leak credentials.

**Recommendation:**
- Add `.env*` to `.gitignore` immediately
- Use a secrets manager (AWS Secrets Manager, HashiCorp Vault, or Doppler) for production secrets
- Rotate any credentials that have ever been committed or stored in plaintext

```bash
# .gitignore
.env
.env.*
*.pem
*.key
```

---

## Prioritised Fix List

| Priority | Finding | OWASP |
|---|---|---|
| 🔴 P0 | Add authentication to `/users` | A01 |
| 🔴 P0 | Add `helmet()` security headers | A05 |
| 🔴 P0 | Add rate limiting | A04 |
| 🟠 P1 | Add body parsing + input validation | A03 |
| 🟠 P1 | Configure CORS allowlist | A05 |
| 🟠 P1 | Add global error handler | A05 |
| 🟠 P1 | Minimise PII in responses | A02 |
| 🟡 P2 | Enforce HTTPS / TLS | A02 |
| 🟡 P2 | Bind to specific interface | A05 |
| 🟡 P2 | Add structured logging | A09 |
| 🟢 P3 | Add `package.json` + `npm audit` | A06 |
| 🟢 P3 | Ensure `.env*` in `.gitignore` | A02 |

---

## Recommended Secure Baseline (`app.js`)

Putting it all together, here is a secure starting point:

```js
'use strict';

const express   = require('express');
const helmet    = require('helmet');
const cors      = require('cors');
const rateLimit = require('express-rate-limit');
const pino      = require('pino');
const pinoHttp  = require('pino-http');

const logger = pino({ level: process.env.LOG_LEVEL || 'info' });
const app = express();

// ── Security middleware ─────────────────────────────────────────
app.disable('x-powered-by');
app.use(helmet());
app.use(cors({
  origin: (process.env.ALLOWED_ORIGINS || '').split(','),
  credentials: true,
}));
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100, standardHeaders: true }));
app.use(pinoHttp({ logger }));

// ── Body parsing ────────────────────────────────────────────────
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// ── Routes ──────────────────────────────────────────────────────
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', requireAuth, (req, res) => {
  // TODO: replace with parameterised DB query; return only needed fields
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob'   },
  ]);
});

// ── Error handling ──────────────────────────────────────────────
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

app.use((err, req, res, _next) => {
  logger.error({ err, path: req.path }, 'Unhandled error');
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal server error' : err.message,
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, '127.0.0.1', () => logger.info(`Server on port ${PORT}`));

module.exports = app;
```

